/**
 * rebuild-dashboard.js
 * Reads claudie-dashboard-data.json (generated by build-dashboard-from-json.js)
 * and injects the data into dashboard.html. No Excel file dependency.
 *
 * Run: node C:\Cursor\toast-mcp-server\rebuild-dashboard.js
 */
import fs from "fs";

const DATA_FILE    = "C:\\Cursor\\toast-mcp-server\\claudie-dashboard-data.json";
const DASH_OUT     = "C:\\Cursor\\toast-mcp-server\\dashboard.html";
const TEMPLATE_PATH = "C:\\Users\\MatthiasLavenant\\AppData\\Local\\Packages\\Claude_pzs8sxrjxfjjc\\LocalCache\\Roaming\\Claude\\local-agent-mode-sessions\\0f67faa4-7928-472e-a9c8-6595dcb9c69a\\aebc4b15-bb6d-49d0-b2dc-590410476945\\local_0dca1049-befc-4ae5-8b8d-fe04fc6e0fa0\\outputs\\dashboard_claudie.html";

const raw = JSON.parse(fs.readFileSync(DATA_FILE, "utf8"));

// ── Build stHourlyFormatted from raw.stations ─────────────────────────────
// raw.stations[].hourly: [{ hour, avg (mins), count }]
const stHourlyFormatted = {};
(raw.stations || []).forEach(s => {
  stHourlyFormatted[s.name] = (s.hourly || [])
    .filter(h => h.count > 0)
    .map(h => ({
      hour:    `${h.hour}-${h.hour + 1}`,
      count:   h.count,
      avg_sec: h.avg !== null ? Math.round(h.avg * 60 * 10) / 10 : 0,
      exp_sec: s.targetMins ? s.targetMins * 60 : 0,
      guests:  0,
    }))
    .sort((a, b) => parseInt(a.hour) - parseInt(b.hour));
});

// ── Build stationsArr ─────────────────────────────────────────────────────
const stationsArr = (raw.stations || []).map(s => ({
  station: s.name,
  count:   s.tickets,
  avg_sec: s.avgSecs,
  exp_sec: s.targetMins ? s.targetMins * 60 : 0,
}));

// ── Build curve in dashboard format ──────────────────────────────────────
const pc = raw.pressureCurve;
const curveArr = (pc.lastWeek.loadLevels || []).map((l, i) => ({
  concurrent: l,
  occ:    pc.lastWeek.countByLoad[i] || 0,
  ful:    pc.lastWeek.avgByLoad[i],
  guests: null,
})).filter(c => c.occ > 0 && c.ful !== null);

const curve3Arr = (pc.prior3Weeks.loadLevels || []).map((l, i) => ({
  concurrent: l,
  occ:    pc.prior3Weeks.countByLoad[i] || 0,
  ful:    pc.prior3Weeks.avgByLoad[i],
  guests: null,
})).filter(c => c.occ > 0 && c.ful !== null);

// ── Build fulfillment heatmap ─────────────────────────────────────────────
const fulGrid = {};
(raw.heatmap || []).forEach(d => {
  fulGrid[d.day] = {};
  d.hours.forEach(h => {
    if (h.avg !== null && h.count > 0) {
      fulGrid[d.day][`${h.hour}-${h.hour + 1}`] = h.avg;
    }
  });
});
const fulDays  = (raw.heatmap || []).map(d => d.day);
const fulHours = [...new Set((raw.heatmap || []).flatMap(d =>
  d.hours.filter(h => h.count > 0).map(h => `${h.hour}-${h.hour + 1}`)
))].sort((a, b) => parseInt(a) - parseInt(b));

// ── Build covers heatmap from raw.covers ──────────────────────────────────
const coversData = raw.covers || { days: [], hours: [], grid: {}, gbk: [], bp_g: null };
const covDays    = coversData.days  || [];
const covHours   = coversData.hours || [];
const covGrid    = coversData.grid  || {};

// ── Breaking point analysis (ticket buckets) ──────────────────────────────
const buckets = {};
curveArr.forEach(c => {
  const bucket = Math.floor((c.concurrent - 1) / 10) * 10;
  const label  = `${bucket + 1}–${bucket + 10}`;
  if (!buckets[label]) buckets[label] = [];
  buckets[label].push(c.ful);
});
const tbk = Object.entries(buckets).map(([bucket, arr]) => ({
  bucket,
  ful: Math.round(arr.reduce((s, v) => s + v, 0) / arr.length * 10) / 10,
}));
const TARGET = raw.kpis.targetMins;
let bp_t = null;
for (let i = 0; i < tbk.length - 1; i++) {
  if (tbk[i].ful > TARGET && tbk[i + 1].ful > TARGET) { bp_t = tbk[i].bucket; break; }
}

// ── Surf data (station × hour matrix) ────────────────────────────────────
const surfStations = Object.keys(stHourlyFormatted);
const surfHours    = [...new Set(
  Object.values(stHourlyFormatted).flatMap(h => h.map(x => x.hour))
)].sort((a, b) => parseInt(a) - parseInt(b));
const surfZ = surfStations.map(st => {
  const hourMap = {};
  (stHourlyFormatted[st] || []).forEach(h => {
    hourMap[h.hour] = h.avg_sec ? Math.round(h.avg_sec / 60 * 10) / 10 : null;
  });
  return surfHours.map(h => hourMap[h] || null);
});

// ── Assemble final D object ───────────────────────────────────────────────
const D = {
  location:  raw.meta.location,
  locations: [
    { label: "Claudie",           slug: "claudie"           },
    { label: "Casa Neos",         slug: "casa_neos"         },
    { label: "AVA Coconut Grove", slug: "ava_coconut_grove" },
    { label: "MILA Miami",        slug: "mila"              },
    { label: "AVA Winter Park",   slug: "ava_winter_park"   },
  ],
  week:      raw.meta.weekRange,
  generated: raw.meta.refreshed,
  threshold: raw.kpis.targetMins,
  kpis: {
    tickets:     raw.kpis.totalTickets,
    avg_ful:     raw.kpis.avgFulfillMins,
    problem:     raw.kpis.problemHours,
    peak_conc:   raw.kpis.peakConcurrent,
    peak_guests: null,
    stations:    raw.kpis.stationCount,
  },
  ful:   { days: fulDays,  hours: fulHours,  grid: fulGrid  },
  cov:   { days: covDays,  hours: covHours,  grid: covGrid  },
  curve:  curveArr,
  curve3: curve3Arr,
  tbk,
  gbk:    coversData.gbk  || [],
  bp_t,
  bp_g:   coversData.bp_g || null,
  surf:   { hours: surfHours, stations: surfStations, z: surfZ },
  stations:  stationsArr,
  st_hourly: stHourlyFormatted,
  items:     (raw.menuItems || []).map(m => ({
    item:     m.item || m.name,
    count:    m.qty  || m.count || 0,
    stations: m.stations || [],
    target:   m.targetMins || null,
    kind:     "food",
    avg_sec:  null,
    avg_time: null,
  })),
};

// ── Read template and inject data ─────────────────────────────────────────
let html;
if (fs.existsSync(TEMPLATE_PATH)) {
  html = fs.readFileSync(TEMPLATE_PATH, "utf8");
} else {
  // Fall back to existing dashboard.html as template
  html = fs.readFileSync(DASH_OUT, "utf8");
}

const dataStart = html.indexOf("const D=");
const dataEnd   = html.indexOf("};const $=", dataStart) + 1;
if (dataStart < 0 || dataEnd < 1) {
  process.stderr.write("Could not find data block in template — writing data-only fallback\n");
  // Write a simple wrapper that loads the data
  const fallback = `<!DOCTYPE html><html><head><title>Claudie · BOH Dashboard</title></head><body>
<script>const D=${JSON.stringify(D)};</script>
<p>Template not found. Data injected as window.D. Open dashboard_claudie.html template first.</p>
</body></html>`;
  fs.writeFileSync(DASH_OUT, fallback);
  console.log("Fallback written (template missing).");
  process.exit(0);
}

const newData = `const D=${JSON.stringify(D)}`;
html = html.slice(0, dataStart) + newData + html.slice(dataEnd);
html = html.replace(/<title>.*?<\/title>/, "<title>Claudie · BOH Dashboard</title>");

fs.writeFileSync(DASH_OUT, html);
console.log("Dashboard written:", DASH_OUT);
console.log("Locations:", D.locations.map(l => l.label).join(", "));
console.log("Stations:", D.stations.length);
console.log("Items:", D.items.length);
console.log("Curve points:", D.curve.length);
console.log("Breaking point:", D.bp_t);
console.log("Heatmap days:", D.ful.days.join(", "));
console.log("Covers days:", D.cov.days.join(", ") || "(none)");
console.log("Generated:", D.generated);
